/*
   --- SCRIPT START -- 
 */

function peckishScriptExternal() {
  /* make our variables local */
  let log = console.context().log;
  let user;
  let world;
  let client;
  let mouse;
  let keyboard;
  /* put script features here */
  function initScriptRunner() {
    // check if hooks loaded well (u need to join game btw)
    log("user");
    log(user);
    log("world");
    log(world);
    log("client");
    log(client);
    log("mouse");
    log(mouse);
    log("keyboard");
    log(keyboard);
    // actual script features code
    function AUTOSPIKE() {
      function sendClientBuild(angleOffset) {
        const TwoPI = Math.PI * 2;
        const myPlayer = world.fast_units[user.id];
        function degreesToRad(deg) {
          return (deg * Math.PI) / 180;
        }
        function findBestSpike() {
          const spikesList = [
            ItemType.WOOD_WALL,
            ItemType.WOOD_DOOR_SPIKE,
            ItemType.STONE_DOOR_SPIKE,
            ItemType.GOLD_DOOR_SPIKE,
            ItemType.DIAMOND_DOOR_SPIKE,
            ItemType.AMETHYST_DOOR_SPIKE,
            ItemType.REIDITE_DOOR_SPIKE,
            ItemType.WOOD_SPIKE,
            ItemType.STONE_SPIKE,
            ItemType.GOLD_SPIKE,
            ItemType.DIAMOND_SPIKE,
            ItemType.AMETHYST_SPIKE,
            ItemType.REIDITE_SPIKE,
          ].reverse();
          for (const spikeID of spikesList) {
            if (
              typeof user.inv.n[spikeID] === "number" &&
              user.inv.n[spikeID] > 0
            ) {
              return spikeID;
            }
          }
          return undefined;
        }
        const currentAngleOffset = degreesToRad(angleOffset);
        if (typeof findBestSpike() === "number" && !user.build.wait) {
          client.socket.send(
            JSON.stringify([
              10,
              findBestSpike(),
              window.Math.floor(
                (((myPlayer.angle + currentAngleOffset + TwoPI) % TwoPI) *
                  255) /
                  TwoPI,
              ),
              0,
            ]),
          );
        }
      }
      const AUTOSPIKE_LOOP_DELAY = 200;
      const AUTOSPIKE_OFFSET_DEGREES = 40;
      function sendBuilds() {
        log("sent multiple builds chunk");
        try {
          sendClientBuild(0);
          sendClientBuild(-AUTOSPIKE_OFFSET_DEGREES);
          sendClientBuild(AUTOSPIKE_OFFSET_DEGREES);
        } catch (err) {
          log(err);
        }
      }
      let buildsInterval;
      window.addEventListener("keydown", (e) => {
        if (e.code === "Space" && !e.repeat) {
          e.preventDefault();
          e.stopImmediatePropagation();
          log("spacebar down");
          // call sendBuilds right now cuz the interval skips the first iteration and only runs after x ms
          sendBuilds();
          buildsInterval = setInterval(sendBuilds, AUTOSPIKE_LOOP_DELAY);
        }
      });
      window.addEventListener("keyup", (e) => {
        if (e.code === "Space") {
          e.preventDefault();
          e.stopImmediatePropagation();
          log("spacebar up");
          clearInterval(buildsInterval);
        }
      });
    }
    function AIMBOT() {
      const textEl = document.createElement("div");
      textEl.textContent = "Aimbot Enabled";
      textEl.style.position = "fixed";
      textEl.style.top = "0";
      textEl.style.left = "50%";
      textEl.style.transform = "translateX(-50%)";
      textEl.style.zIndex = "9999999999999";
      textEl.style.fontFamily =
        "system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif";
      textEl.style.fontSize = "20px";
      textEl.style.fontWeight = "600";
      //  textEl.style.lineHeight = "1.4";
      //  textEl.style.padding = "8px 14px";
      //  textEl.style.background = "rgba(0, 0, 0, 0.75)";
      textEl.style.color = "white";
      //  textEl.style.borderRadius = "0 0 12px 12px";
      textEl.style.textAlign = "center";
      textEl.style.pointerEvents = "none";
      document.body.appendChild(textEl);
      function toggleTextVisibility() {
        const isHidden = textEl.style.visibility === "hidden";
        textEl.style.visibility = isHidden ? "visible" : "hidden";
      }
      let isToggled = true;
      window.addEventListener("keydown", (e) => {
        if (e.code === "KeyE" && !e.repeat) {
          isToggled = !isToggled;
          toggleTextVisibility();
        }
      });
      const itemTypeNameByValue = new Map(
        Object.entries(ItemType).map(([name, value]) => [value, name]),
      );
      const getWeaponType = (itemValue) => {
        const itemName = itemTypeNameByValue.get(itemValue) || "";
        if (itemName.includes("PIRATE")) return "PIRATE";
        if (itemName.includes("SPEAR")) return "SPEAR";
        if (itemName.includes("SWORD")) return "SWORD";
        return null;
      };
      const dmgRange = (player) => {
        switch (getWeaponType(player?.right)) {
          case "SWORD":
            return 140;
          case "SPEAR":
            return 200;
          case "PIRATE":
            return 150;
          default:
            return -1;
        }
      };
      let isAutoHitting = false;
      let blockMouseMove = false;
      let mouseMoveBlockerInstalled = false;
      const installMouseMoveBlocker = () => {
        if (mouseMoveBlockerInstalled) return;
        mouseMoveBlockerInstalled = true;
        const block = (e) => {
          if (!blockMouseMove) return;
          e.preventDefault();
          e.stopImmediatePropagation();
          e.stopPropagation();
        };
        window.addEventListener("mousemove", block, true);
        document.addEventListener("mousemove", block, true);
        document.documentElement?.addEventListener("mousemove", block, true);
        document.body?.addEventListener("mousemove", block, true);
      };
      const startHitting = () => {
        mouse.state = mouse.DOWN ?? 1;
        blockMouseMove = true;
        isAutoHitting = true;
      };
      const stopHitting = () => {
        if (!isAutoHitting) return;
        client.stop_attack();
        mouse.state = mouse.UP ?? 0;
        blockMouseMove = false;
        isAutoHitting = false;
      };
      const lockMouseToEnemy = (enemyPlayer) => {
        mouse.pos.x = user.cam.x + enemyPlayer.x;
        mouse.pos.y = user.cam.y + enemyPlayer.y;
      };
      function doTheAiming() {
        installMouseMoveBlocker();
        if (!isToggled) {
          stopHitting();
          window.requestAnimationFrame(doTheAiming);
          return;
        }
        const myPlayer = world.fast_units[user.id];
        if (!myPlayer) {
          stopHitting();
          window.requestAnimationFrame(doTheAiming);
          return;
        }
        let myPlayerData = null;
        const enemyPlayerList = [];
        for (const player of world.units[ITEMS.PLAYERS]) {
          if (player.pid === myPlayer.pid) {
            myPlayerData = {
              x: player.r.x,
              y: player.r.y,
              right: player.right,
              fly: player.fly,
              pid: player.pid,
            };
            continue;
          }
          if (
            myPlayer.fly === player.fly &&
            player.pid !== myPlayer.pid &&
            !user.team.includes(player.pid)
          ) {
            enemyPlayerList.push({
              x: player.r.x,
              y: player.r.y,
              fly: player.fly,
              pid: player.pid,
            });
          }
        }
        if (!myPlayerData) {
          stopHitting();
          window.requestAnimationFrame(doTheAiming);
          return;
        }
        let closestEnemyPlayer = null;
        let closestDistanceSq = Infinity;
        for (const enemyPlayer of enemyPlayerList) {
          const dx = enemyPlayer.x - myPlayerData.x;
          const dy = enemyPlayer.y - myPlayerData.y;
          const distanceSq = dx * dx + dy * dy;
          if (distanceSq < closestDistanceSq) {
            closestDistanceSq = distanceSq;
            closestEnemyPlayer = enemyPlayer;
          }
        }
        const range = dmgRange(myPlayerData);
        const enemyIsInRange =
          closestEnemyPlayer && range > 0 && closestDistanceSq <= range * range;
        if (enemyIsInRange) {
          const dx = closestEnemyPlayer.x - myPlayerData.x;
          const dy = closestEnemyPlayer.y - myPlayerData.y;
          const angleToClosestEnemy = Math.atan2(dy, dx);
          startHitting();
          lockMouseToEnemy(closestEnemyPlayer);
        } else {
          stopHitting();
        }
        window.requestAnimationFrame(doTheAiming);
      }
      doTheAiming();
    }
    // execute script features
    AUTOSPIKE();
    AIMBOT();
  }
  /* hooking logic */
  let hookingInterval;
  function hookGameObjects() {
    if (
      window.globalWorld &&
      window.globalUser &&
      window.globalClient &&
      window.globalMouse &&
      window.globalKeyboard
    ) {
      user = window.globalUser;
      world = window.globalWorld;
      client = window.globalClient;
      mouse = window.globalMouse;
      keyboard = window.globalKeyboard;
      initScriptRunner();
      clearInterval(hookingInterval);
    }
  }
  hookingInterval = setInterval(hookGameObjects, 100);
}
peckishScriptExternal();
/*
   --- SCRIPT END -- 
 */

(() => {
  const createMemoryStorage = () => {
    const store = Object.create(null);
    return {
      getItem(key) {
        const value = store[String(key)];
        return value === undefined ? null : value;
      },
      setItem(key, value) {
        store[String(key)] = String(value);
      },
      removeItem(key) {
        delete store[String(key)];
      },
      clear() {
        for (const key of Object.keys(store)) delete store[key];
      },
      key(index) {
        const keys = Object.keys(store);
        return keys[index] ?? null;
      },
      get length() {
        return Object.keys(store).length;
      },
    };
  };
  const buildSafeStorage = (nativeStorage) => {
    const fallback = createMemoryStorage();
    return {
      getItem(key) {
        try {
          return nativeStorage
            ? nativeStorage.getItem(key)
            : fallback.getItem(key);
        } catch (_) {
          return fallback.getItem(key);
        }
      },
      setItem(key, value) {
        try {
          return nativeStorage
            ? nativeStorage.setItem(key, value)
            : fallback.setItem(key, value);
        } catch (_) {
          return fallback.setItem(key, value);
        }
      },
      removeItem(key) {
        try {
          return nativeStorage
            ? nativeStorage.removeItem(key)
            : fallback.removeItem(key);
        } catch (_) {
          return fallback.removeItem(key);
        }
      },
      clear() {
        try {
          return nativeStorage ? nativeStorage.clear() : fallback.clear();
        } catch (_) {
          return fallback.clear();
        }
      },
      key(index) {
        try {
          return nativeStorage ? nativeStorage.key(index) : fallback.key(index);
        } catch (_) {
          return fallback.key(index);
        }
      },
      get length() {
        try {
          return nativeStorage ? nativeStorage.length : fallback.length;
        } catch (_) {
          return fallback.length;
        }
      },
    };
  };
  const resolveNativeStorage = (name) => {
    try {
      const storage = window[name];
      if (!storage) return null;
      const testKey =
        "__peckish_storage_probe__" + Math.random().toString(36).slice(2);
      storage.setItem(testKey, "1");
      storage.removeItem(testKey);
      return storage;
    } catch (_) {
      return null;
    }
  };
  const safeLocalStorage = buildSafeStorage(
    resolveNativeStorage("localStorage"),
  );
  const safeSessionStorage = buildSafeStorage(
    resolveNativeStorage("sessionStorage"),
  );
  window.__peckishSafeStorage = safeLocalStorage;
  window.__peckishSafeSessionStorage = safeSessionStorage;
  // Prevent hard-freeze when inline anti-cheat is blocked/cached out-of-order:
  // client network path should stay functional in fallback mode.
  if (typeof window.__peckishAnticheatLoaded === "undefined") {
    window.__peckishAnticheatLoaded = true;
  }
  if (typeof window.__peckishTamperBlocked === "undefined") {
    window.__peckishTamperBlocked = false;
  }
})();
var localStorage = window.__peckishSafeStorage;
var sessionStorage = window.__peckishSafeSessionStorage;

